// Slice 0 / Fase C (v2) - lee el raw body desde BINARIO ('data'), no desde $json.rawBody.
// En esta version de n8n, el Webhook con "Raw Body" ON entrega el cuerpo crudo como
// binario (item.binary.data), no como rawBody. getBinaryDataBuffer da los bytes exactos.
const crypto = require('crypto');

// Secreto: prioridad Variables ($vars); fallback in-node (sanitizado en el template).
const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';

const item = $input.first();
const wh = item.json;

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody.
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) {
  return [{ json: { ok_firma: false, motivo: 'raw_body_ausente', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 2) Firma recibida en el header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe (requiere igual longitud).
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) {
  return [{ json: { ok_firma: false, motivo: 'firma_invalida', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return [{ json: { ok_firma: false, motivo: 'payload_invalido', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 6) Ventana de ts (anti-replay liviano, D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return [{ json: { ok_firma: false, motivo: 'ts_fuera_de_ventana', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts: body.ts ?? null } }];
}

return [{ json: { ok_firma: true, motivo: null, ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts } }];

// Slice 0 / Fase C - compara ambiente y arma el envelope uniforme (D-C-18/35).
const v = $('validar_firma_ts').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'cuerpo no es JSON valido',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

return [{ json: { ok: true, data: { ambiente: real, rol: v.rol } } }];
